399	function checkIfAnyFiltersSelected(jNode, position) {
400	            const filterDivs = document.querySelectorAll(`.dds__srchby-filter-${jNode}`);
401	
402	            if (filterDivs.length <= position) return false;
403	
404	            for (var i = position; i < filterDivs.length; i++) {
405	                const checkbox = filterDivs[i].querySelector('input.dds__checkbox__input');
406	                if (checkbox && checkbox.checked) {
407	                    return true;
408	                }
409	            }
410	            return false;
411	        }
