let clearAllFlag = false;
let isCheckboxChange = false;

let autoCompleteTimeout = null;
const AUTOCOMPLETE_DELAY = 300; // milliseconds
const MIN_CHARS_AUTOCOMPLETE = 2;
let switchEle = "";
let $mlCatEle = "";
let $mlModEle = "";
let srchPaginationElement;

$jq(document).ready(function(){
