        const srchFltrHintInit = DDS.MessageBar(srchFltrHintelement);

        srchFltrHintInit.show();

        srchFltrHintelement.addEventListener("ddsMessageBarHiddenEvent", (e) => {
        	sessionStorage.setItem("hideSrchFltrHint", "true");
        });
	} else {
			const srchFltrHintelement = document.getElementById("dds__msgBar-filterHint");
            srchFltrHintelement.classList.add("dds__d-none");
    }

    $jq(".dds__icon--search").unbind('click').click(function(){
        if($jq("#dds__srch-input").val().trim() != "" && $jq("#dds__srch-input").val().trim() != null){
            logSearch(apiResponseObj);
            $emptySrchMBarApi.hide();
//            resetPagination();
            updateURL();
            init();
        } else {
    	    $emptySrchMBarApi.show();
        }
    });

    $jq("#dds__srch-input").unbind('keyup').keyup(function(event) {
        if (event.keyCode === 13) {
        if($jq("#dds__srch-input").val().trim() != "" && $jq("#dds__srch-input").val().trim() != null){
            logSearch(apiResponseObj);
            $emptySrchMBarApi.hide();
//            resetPagination();
            updateURL();
            init();
        } else {
        	$emptySrchMBarApi.show();
        }
        }
    });

    $jq(".dds__icon--close-cir").unbind('click').click(function(){
    	$jq("#dds__srch-input").val("");
        $emptySrchMBarApi.hide();
        $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
        updateURL();
        var tagid = $jq(".dds__tag[data-cbmap=searchBy]").attr("id");
        var tagDiv = document.getElementById(tagid);
        var dismissButton = tagDiv.querySelector('button:nth-of-type(2)');

        dismissButton.click();
        init();
    });

    $jq(".dt-clear-all").off('click').on("click", function() {
        if ($jq(".dds__tag").length) {
            clearAllFlag = true;

            $jq(document).off('ddsTagDismissEvent');

            $jq(window).off('popstate');

            const tagsToRemove = [];
            $jq(".dds__tag").each(function() {
                tagsToRemove.push({
                    cbmap: $jq(this).data("cbmap"),
                    tagid: $jq(this).attr("id")
                });
            });

            const certSwitch = document.getElementById('dds__cert-switch');
            if (certSwitch) {
                certSwitch.removeEventListener('ddsSwitchChangeEvent', certSwitchHandler);
                if (certSwitch.getAttribute('aria-checked') === 'true') {
                    switchEle.toggleChecked();
                }
            }

            $jq("#dy-table-accordion-Categories .dds__checkbox__input:checked, #dy-table-accordion-Type .dds__checkbox__input:checked")
                .each(function() {
                    $jq(this).prop('checked', false);
                });

            $jq("#dds__srch-input").val("");

