                $jq(`#${tag.tagid}`).remove();
            });

            $jq(".dds__price-error").addClass("dds__d-none");
            $jq(".filter-clearAll").addClass("dds__d-none");
            $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");

            coveocurrentPage = 1;
//            resetPagination();
            updatePaginationUI(1);
