function initSrchPagination(id, totalRows, filterObj) {
    if (!srchPaginationElement) {
        srchPaginationElement = document.getElementById(id);
        api = DDS.Pagination(srchPaginationElement, {
            currentPage: coveocurrentPage,
            itemsPerPage: pageSize
        });
    }

    srchPaginationElement.removeEventListener("ddsPaginationPageChangedEvent", handlePaginationChange);
    srchPaginationElement.removeEventListener("ddsPaginationPageSizeChangedEvent", handlePaginationChange);

    api.setTotalItems(totalRows);

    const startRange = ((coveocurrentPage - 1) * pageSize) + 1;
    const endRange = Math.min(coveocurrentPage * pageSize, totalRows);

    let srchPgnTop = `Results <strong>${startRange} - ${endRange}</strong> of <strong>${totalRows}</strong>`;

    if (searchInput.value != "") {
        srchPgnTop = srchPgnTop + ` for <strong>${searchInput.value}</strong>`;
    }

    $jq(".dds__srch-pagination-top").html(srchPgnTop);
    $jq("#pagination-current-page-886179417").val(coveocurrentPage.toString());

    srchPaginationElement.addEventListener("ddsPaginationPageChangedEvent", handlePaginationChange);
    srchPaginationElement.addEventListener("ddsPaginationPageSizeChangedEvent", handlePaginationChange);
}

function handlePaginationChange(e) {
    paginationClick(e, "ddsPaginationPageChangedEvent", filterObj, apiResponseObj.totalCount);
    scrollToDiv();
}

function paginationClick(e, type, filterObj, totalRows) {
    accordFlag = true;

    if (type === "ddsPaginationPageChangedEvent") {
        pageSize = parseInt(e.detail.pageSize);
        coveocurrentPage = e.detail.currentPage;
    } else if (type === "ddsPaginationPageSizeChangedEvent") {
        pageSize = parseInt(e.detail.pageSize);
        coveocurrentPage = 1;
    }

    triggerStoreSearchAPI($jq.trim(apiUrl));
}


