var existingTag = "";

function addFilterTag(element, type) {
    var tagText = "";
    var tagHtml = "";

    if (type === "filterby") {
        tagText = DOMPurify.sanitize($jq(element).val());
        existingTag = $jq(`.dt-search-tags .dds__tag:contains(${tagText})`);
    } else if (type === "searchBy") {
        tagText = DOMPurify.sanitize($jq(element).text() || $jq(element).val());
        existingTag = $jq(".dt-search-tags .dds__tag[data-cbmap='searchBy']");
    } else if (type === "priceRange") {
        if ($jq("#dds__price-min").val() === "0" && $jq("#dds__price-max").val() === "0") {
             tagText = "0 USD";
        } else {
            tagText = `${$jq("#dds__price-min").val()} - ${$jq("#dds__price-max").val()}`;
        }
        existingTag = $jq(".dt-search-tags .dds__tag[data-cbmap='priceRange']");
    }

    if (existingTag.length > 0) {
        existingTag.remove();
    }

    var randomNumber = generateRandomId();
    tagHtml = `
        <div data-dds="tag" id="dy-table-tag-${randomNumber}" class="dds__tag dds__tag--sm dds__mt-1 dds__mb-1 dds__mr-2" data-dismiss="true" data-cbmap="${type === 'filterby' ? $jq(element).attr("id") : type}" data-sr-dismiss="dismiss">
            <button type="button">${tagText}</button>
        </div>`;

    if (type === "searchBy") {
        $jq(element).val(tagText);
    }

    $jq(".dt-search-tags").append(tagHtml);
    initTag(`dy-table-tag-${randomNumber}`);
    $jq(".filter-clearAll").removeClass("dds__d-none");
}

