    updateURL();
//    resetPagination();

    const hasCategorySelectionBeyond5 = checkIfAnyFiltersSelected('epcategory', 5);
    const hasTypeSelectionBeyond5 = checkIfAnyFiltersSelected('epmodalitycourse', 5);

    const categoryMoreLess = document.querySelector('.dds__mlbtn-epcategory');
