function getDeviceFromUserAgent(userAgent) {
    if (/chrome/i.test(userAgent)) return "Chrome";
    if (/firefox/i.test(userAgent)) return "Firefox";
    if (/safari/i.test(userAgent)) return "Safari";
    if (/msie|trident/i.test(userAgent)) return "IE";
    if (/edge/i.test(userAgent)) return "Edge";
    return "Other";
}

function isMobileDevice(userAgent) {
    return /Android.+Mobile|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini|Windows Phone|Kindle|Silk|Mobile Safari/i.test(userAgent) && !(/iPad|Android(?!.*Mobile)|Tablet|Silk.*Tablet/i.test(userAgent));
}

function sendApiRequest(endpoint, payload, clickUrl) {

    const currentHostname = window.location.hostname;

    let apiUrl;
    if (currentHostname.includes('learning.dell')) {
        apiUrl = `https://dellprod.analytics.org.coveo.com/rest/ua/v15/analytics/${endpoint}?org=dellprod`;
    } else {
        apiUrl = `https://dellsandbox2.analytics.org.coveo.com/rest/ua/v15/analytics/${endpoint}?org=dellsandbox2`;
    }

    console.log(`Sending ${apiUrl} request:`, payload);

    const bearerToken = apiResponseObj && apiResponseObj.metadata && apiResponseObj.metadata['sbt-client']
            ? apiResponseObj.metadata['sbt-client']
            : '';

    const finalPayload = endpoint === 'searches' ? [payload] : payload;

    $jq.ajax({
        url: apiUrl,
        type: "POST",
        data: JSON.stringify(finalPayload),
        contentType: "application/json",
        dataType: "json",
        headers: {
            "Authorization": `Bearer ${bearerToken}`,
            "Content-Type": "application/json"
        },
        success: function(response) {
            console.log(`${apiUrl} request successful:`, response);
            if(clickUrl){
                setTimeout(function() {
                    window.location = clickUrl;
                }, 500);
            }
        },
        error: function(error) {
            console.error(`${apiUrl} request failed:`, error);
            if(clickUrl){
                setTimeout(function() {
                    window.location = clickUrl;
                }, 500);
            }
        }
    });
}
